def find_duplicates(items):
    """Find duplicate items in a list — O(n) time, O(n) space."""
    seen = set()
    duplicates = []
    for item in items:
        if item in seen:
            duplicates.append(item)
        else:
            seen.add(item)
    return duplicates


def count_occurrences(text, words):
    """Count occurrences of each word in text — O(t + w) time."""
    word_counts = Counter(text.split())
    return {word: word_counts.get(word, 0) for word in words}"}
